def parse_nombre(raw):
    toks = ' '.join(raw.split()).split()
    if len(toks) < 3:
        return {'raw': raw, 'status': 'review', 'given': ' '.join(toks), 'ap1': None, 'ap2': None}
    return {'raw': raw, 'status': 'ok', 'given': ' '.join(toks[:-2]), 'ap1': toks[-2], 'ap2': toks[-1]}
for s in ['Madonna', 'Luis Quispe Huamán']:
    print(parse_nombre(s))

